import React, { useState, useEffect } from "react";

// Screens
import SplashScreen from "./screens/SplashScreen.jsx";
import SignInScreen from "./screens/SignInScreen.jsx";
import SignUpScreen from "./screens/SignUpScreen.jsx";
import Dashboard from "./screens/Dashboard.jsx";
import HomeScreen from "./screens/HomeScreen.jsx";
import GoalsScreen from "./screens/GoalsScreen.jsx";
import LoansScreen from "./screens/LoansScreen.jsx";
import ProfileScreen from "./screens/ProfileScreen.jsx";
import TransactionHistoryScreen from "./screens/TransactionHistoryScreen.jsx";
import DepositScreen from "./screens/DepositScreen.jsx";
import WithdrawScreen from "./screens/WithdrawScreen.jsx";
import SavingsDepositScreen from "./screens/SavingsDepositScreen.jsx";

// modals
import AddGoalModal from "./modals/AddGoalModal.jsx";
import DepositWithdrawModal from "./modals/DepositWithdrawModal.jsx";
import GoalDetailModal from "./modals/GoalDetailModal.jsx";
import LoanDetailModal from "./modals/LoanDetailModal.jsx";
import TakeLoanModal from "./modals/T"
// Icons
import { Home, Target, CreditCard, User } from "lucide-react";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Splash");
  const [tab, setTab] = useState("Home");

  // Mock user and data
  const [user, setUser] = useState({ name: "Faith Bode", email: "faith@example.com", joinedDate: "Jan 2025" });
  const [balance, setBalance] = useState(1500);
  const [savingsBalance, setSavingsBalance] = useState(300);
  const [goals, setGoals] = useState([
    { id: 1, title: "Buy PS5", description: "Save for PS5 console", amountSaved: 100, targetAmount: 500 },
  ]);
  const [loans, setLoans] = useState([]);
  const [transactions, setTransactions] = useState([
    { id: 1, title: "Deposit to account", description: "Deposit into account", amount: 10, id: Date.now() }
  ]);

  // Splash -> SignIn simulation
  useEffect(() => {
    const timer = setTimeout(() => setCurrentScreen("SignIn"), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Transaction handlers
  const handleDeposit = (amount) => {
    setBalance(balance + amount);
    setTransactions([{ id: Date.now(), type: "deposit", title: "Deposit", amount, date: new Date().toLocaleDateString() }, ...transactions]);
  };

  const handleWithdraw = (amount) => {
    setBalance(balance - amount);
    setTransactions([{ id: Date.now(), type: "withdraw", title: "Withdrawal", amount, date: new Date().toLocaleDateString() }, ...transactions]);
  };

  const handleSavingsDeposit = (amount) => {
    setSavingsBalance(savingsBalance + amount);
    setBalance(balance - amount);
    setTransactions([{ id: Date.now(), type: "deposit", title: "Savings Deposit", amount, date: new Date().toLocaleDateString() }, ...transactions]);
  };

  // Screen rendering
  const renderScreen = () => {
    switch (currentScreen) {
      case "Splash":
        return <SplashScreen onFinish={() => setCurrentScreen("SignIn")} />;
      case "SignIn":
        return <SignInScreen onSignIn={() => setCurrentScreen("Dashboard")} />;
      case "SignUp":
        return <SignUpScreen onSignUp={() => setCurrentScreen("Dashboard")} />;
      case "Dashboard":
        // Tabs
        switch (tab) {
          case "Home":
            return <HomeScreen balance={balance} transactions={transactions} setModal={setCurrentScreen} userName={user.name} getGreeting={() => "Hello"} />;
          case "Goals":
            return <GoalsScreen goals={goals} />;
          case "Loans":
            return <LoansScreen loans={loans} />;
          case "Profile":
            return <ProfileScreen user={user} />;
          default:
            return <HomeScreen balance={balance} transactions={transactions} setModal={setCurrentScreen} userName={user.name} getGreeting={() => "Hello"} />;
        }
      case "Transactions":
        return <TransactionHistoryScreen transactions={transactions} />;
      case "Deposit":
        return <DepositScreen onDeposit={handleDeposit} />;
      case "Withdraw":
        return <WithdrawScreen onWithdraw={handleWithdraw} balance={balance} />;
      case "SavingsDeposit":
        return <SavingsDepositScreen onDeposit={handleSavingsDeposit} savingsBalance={savingsBalance} />;
      default:
        return <HomeScreen balance={balance} transactions={transactions} setModal={setCurrentScreen} userName={user.name} getGreeting={() => "Hello"} />;
    }
  };

  // Bottom nav
  const tabs = [
    { key: "Home", label: "Home", icon: Home },
    { key: "Goals", label: "Goals", icon: Target },
    { key: "Loans", label: "Loans", icon: CreditCard },
    { key: "Profile", label: "Profile", icon: User },
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <div className="flex-1">{renderScreen()}</div>

      {currentScreen === "Dashboard" && (
        <nav className="bg-white border-t border-gray-200 px-6 py-2 flex justify-between items-center fixed bottom-0 left-0 w-full">
          {tabs.map((t) => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={`flex flex-col items-center justify-center flex-1 py-2 ${
                tab === t.key ? "text-teal-600" : "text-gray-400"
              }`}
            >
              <t.icon className="w-6 h-6" />
              <span className="text-xs mt-1">{t.label}</span>
            </button>
          ))}
        </nav>
      )}
    </div>
  );
}
